```typescript
function solve(n: number, edges: number[][], k: number): number {
    // Sort edges by time to process them in order
    edges.sort((a, b) => a[2] - b[2]);

    // Union-Find (Disjoint Set Union) data structure
    const parent: number[] = Array(n).fill(0).map((_, i) => i);
    const rank: number[] = Array(n).fill(0);

    function find(x: number): number {
        if (parent[x] !== x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    function union(x: number, y: number): boolean {
        const rootX = find(x);
        const rootY = find(y);
        if (rootX === rootY) return false;
        if (rank[rootX] > rank[rootY]) {
            parent[rootY] = rootX;
        } else if (rank[rootX] < rank[rootY]) {
            parent[rootX] = rootY;
        } else {
            parent[rootY] = rootX;
            rank[rootX]++;
        }
        return true;
    }

    // We'll use a binary search approach to find the minimum time t
    let left = 0;
    let right = 1e9;
    let result = 1e9;

    // First, check if the initial number of connected components is already >= k
    let components = n;
    for (let i = 0; i < n; i++) {
        parent[i] = i;
    }
    for (let i = 0; i < edges.length; i++) {
        const [u, v, time] = edges[i];
        if (find(u) !== find(v)) {
            union(u, v);
            components--;
        }
    }

    if (components >= k) {
        return 0;
    }

    // Binary search for the minimum time t
    while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        // Reset parent and rank for each binary search step
        parent.fill(0).map((_, i) => parent[i] = i);
        rank.fill(0);
        components = n;
        for (let i = 0; i < edges.length; i++) {
            const [u, v, time] = edges[i];
            if (time > mid) {
                if (find(u) !== find(v)) {
                    union(u, v);
                    components--;
                }
            }
        }

        if (components >= k) {
            result = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return result;
}
